"use client";

import { useBreathPace, type BreathPhase } from "../hooks/useBreathPace";
import { usePrefersReducedMotion } from "../hooks/usePrefersReducedMotion";

/**
 * The breath-paced cue — the ceremonial clock of the page.
 *
 * A small matcha circle breathes on a 4-4-4 cycle (inhale · hold · exhale ·
 * rest), and under it a romanized label cross-fades as the phase turns. The
 * cue is the only thing on the hero that moves; everything else waits. It is
 * the mechanic that makes the page feel paced like a tea rite rather than a
 * landing page.
 *
 * - The scale is a CSS animation keyed off `data-breath={phase}` so it runs
 *   off the compositor (transform only), not off React state per frame.
 * - `useBreathPace` returns the phase; reduced motion pins it to "rest" and
 *   the circle simply sits, full and still.
 * - `active` pauses the cycle when the hero leaves the viewport (handled by
 *   the parent via an IntersectionObserver), so no timer runs offscreen.
 *
 * The cue never blocks reading: it is decorative (aria-hidden) and the four
 * beats are listed in plain text beside it for assistive tech.
 */
const PHASE_LABEL: Record<BreathPhase, { ja: string; en: string }> = {
  0: { ja: "吸う", en: "inhale" },
  1: { ja: "止む", en: "hold" },
  2: { ja: "吐く", en: "exhale" },
  3: { ja: "間", en: "ma — the pause between" },
};

export default function BreathCue({ active }: { active: boolean }) {
  const reduced = usePrefersReducedMotion();
  const phase = useBreathPace(active, reduced);
  const label = PHASE_LABEL[phase];

  return (
    <div
      className="chado-breath"
      data-breath={phase}
      aria-hidden="true"
    >
      <span className="chado-breath__orb" />
      <span className="chado-breath__rings">
        <span className="chado-breath__ring chado-breath__ring--1" />
        <span className="chado-breath__ring chado-breath__ring--2" />
      </span>
      <span className="chado-breath__label" key={phase}>
        <span className="chado-breath__ja" lang="ja">
          {label.ja}
        </span>
        <span className="chado-breath__en">{label.en}</span>
      </span>
    </div>
  );
}

// Re-exported for the parent's IntersectionObserver typing convenience.
export type { BreathPhase };

"use client";

import type { ReactNode } from "react";
import { usePrefersReducedMotion } from "../hooks/usePrefersReducedMotion";
import { useScrollProgress } from "../hooks/useScrollProgress";

/**
 * The chasen (茶筅) draw-on — the second signature technique.
 *
 * The matcha preparation is shown as a brush-stroke draw-on: the bamboo
 * whisk's tines fan out from a single node as the guest scrolls, the bowl
 * fills beneath it, and only at the end does the matcha surface bloom — the
 * green that the whole ceremony was building toward. Every stroke is a
 * pathLength=1 path whose dashoffset is the inverse of scroll progress:
 *   stroke-dashoffset: calc(1 - var(--ch-scrub, 1))
 * The whisk draws exactly as far as the guest has scrolled, and no further.
 *
 * The scene pins (position: sticky inside a tall scene column) while the
 * accompanying text — the four-step preparation, set bilingually — flows
 * past. The scrub window is centered on the scene so the whisk moves only
 * while its chashitsu is the room you are in.
 *
 * Reduced motion / no JS: `--ch-scrub` defaults to 1, so every tine is
 * drawn and the bowl is full — a completed preparation, statically waiting.
 * The pin releases to a static figure.
 */
function Whisk() {
  // 17 bamboo tines fan from a node at (140, 96) up to the bowl rim.
  // pathLength=1 each so dashoffset math stays in the head.
  const tines = Array.from({ length: 17 }, (_, i) => {
    const t = i / 16; // 0..1 across the fan
    const spread = (t - 0.5) * 2; // -1..1
    const topX = 140 + spread * 46;
    const topY = 26 + Math.abs(spread) * 6; // slight arc, longer at center
    const cx = 140 + spread * 30;
    const cy = 64 + Math.abs(spread) * 3;
    return `M 140 96 C ${cx} ${cy}, ${cx - spread * 4} ${
      (cy + topY) / 2
    }, ${topX} ${topY}`;
  });

  return (
    <g className="chado-chasen__group">
      {/* the handle — a single bamboo prong descending from the node */}
      <path
        className="chado-chasen__handle"
        d="M 140 96 C 138 120, 137 140, 136 158"
        pathLength={1}
      />
      {/* the node where the tines are bound */}
      <ellipse
        className="chado-chasen__node"
        cx="140"
        cy="96"
        rx="13"
        ry="4.2"
      />
      {/* the fanning tines — drawn progressively by scroll */}
      {tines.map((d, i) => (
        <path
          key={i}
          className={`chado-chasen__tine${
            i % 3 === 0 ? " chado-chasen__tine--inner" : ""
          }`}
          d={d}
          pathLength={1}
        />
      ))}
    </g>
  );
}

function Bowl() {
  return (
    <g className="chado-bowl__group">
      {/* the chawan outline — one continuous tea-bowl stroke */}
      <path
        className="chado-bowl__shell"
        d="M 70 200 C 74 250, 102 282, 140 282 C 178 282, 206 250, 210 200 Z"
        pathLength={1}
      />
      {/* the rim ellipse, seen from above */}
      <ellipse
        className="chado-bowl__rim"
        cx="140"
        cy="200"
        rx="70"
        ry="13"
      />
      {/* the matcha surface — blooms in only as preparation completes
          (opacity calc(scrub·5 − 4) maps scrub 0.8→1 onto 0→1) */}
      <ellipse
        className="chado-bowl__tea"
        cx="140"
        cy="201"
        rx="62"
        ry="9.5"
      />
      {/* the foam — two small crescents where the whisk has passed */}
      <path
        className="chado-bowl__foam"
        d="M 112 199 q 12 -5 24 0 M 150 202 q 10 -4 20 0"
        pathLength={1}
      />
    </g>
  );
}

export default function ChasenDraw({ notes }: { notes: ReactNode }) {
  const reduced = usePrefersReducedMotion();
  const sceneRef = useScrollProgress<HTMLDivElement>(reduced);

  return (
    <section
      id="chado-preparation"
      className="chado-chashitsu"
      aria-labelledby="chado-preparation-title"
    >
      <header className="chado-chashitsu__head" data-reveal>
        <p className="chado-kicker">
          <span lang="ja">点前</span> · The Preparation
        </p>
        <h2
          id="chado-preparation-title"
          className="chado-section-title"
          lang="ja"
        >
          茶筅が描く一服
        </h2>
        <p className="chado-section-sub">
          A bowl drawn by the whisk — chasen, bowl, breath.
        </p>
      </header>

      <div ref={sceneRef} className="chado-chashitsu__scene">
        <figure className="chado-chashitsu__plate">
          <svg
            className="chado-chashitsu__art"
            viewBox="0 0 280 300"
            role="img"
            aria-labelledby="chado-chasen-label"
          >
            <title id="chado-chasen-label">
              茶筅が茶碗の上で点てる図 — 竹の茶筅がスクロールに合わせて 그림지며,
              한 그릇의 말차가 완성된다. The bamboo chasen whisking above the
              chawan; its tines draw as you scroll, until one bowl of matcha
              is complete.
            </title>
            <Whisk />
            <Bowl />
          </svg>
          <figcaption className="chado-chashitsu__cap">
            <span lang="ja">
              図 · 茶筅（ちゃせん）— 竹を割って曲げた七十本の穂が、一碗の泡を立てる。
            </span>
            <em>
              Plate · the chasen — bamboo split and bent into seventy tines,
              which raise the foam of a single bowl.
            </em>
          </figcaption>
        </figure>

        <div className="chado-chashitsu__text">{notes}</div>
      </div>
    </section>
  );
}

"use client";

import { useEffect, useState } from "react";

/**
 * The breath-paced scroll mechanic — the signature of the entry.
 *
 * A tea ceremony is paced in breaths, not minutes. This hook drives the
 * hero's breathing cue through a 4-4-4 cycle (the box-breath the guest is
 * taught at the roji gate): inhale 4s · hold 4s · exhale 4s · rest 2s — a
 * 14-second bow. The cue is a circle that scales with the breath; under it
 * a romanized label (吸う · hold · 吐く) cross-fades as the phase turns. The
 * whole page is implicitly paced by it: content arrives, then waits. The
 * opposite of busy.
 *
 * The cycle is driven by a phase index (0..3) derived from elapsed time, so
 * it never drifts and never desyncs between the scale animation (CSS) and
 * the label (React). Phases:
 *   0 inhale  (4.0s)  — scale 0.92 → 1.00, ease-out
 *   1 hold    (4.0s)  — scale 1.00, still
 *   2 exhale  (4.0s)  — scale 1.00 → 0.92, ease-in
 *   3 rest    (2.0s)  — scale 0.92, still (the ma between breaths)
 *
 * Discipline (rubric gates G2/G3):
 * - The hook returns the phase; the scale itself is a pure CSS animation
 *   keyed off `data-breath`, so the rAF budget is one setInterval tick per
 *   second, not per frame. (A 14s cycle does not need frame precision — the
 *   eye reads the scale continuously, the label only at the turn.)
 * - Stops entirely under reduced motion (returns phase "rest" statically,
 *   the page composes without the cue).
 * - Pauses when the tab is hidden and when the hero is offscreen (passed in
 *   as `active`), so no rAF or timer runs for an offscreen cue.
 * - SSR-safe: the initial state is the inhale phase, so the server render
 *   matches the first client paint.
 */
export type BreathPhase = 0 | 1 | 2 | 3;

export const BREATH_DURATIONS: Record<BreathPhase, number> = {
  0: 4000, // inhale
  1: 4000, // hold
  2: 4000, // exhale
  3: 2000, // rest
} as const;

export const BREATH_CYCLE_MS = Object.values(BREATH_DURATIONS).reduce(
  (a, b) => a + b,
  0,
); // 14000

export function useBreathPace(active: boolean, disabled: boolean): BreathPhase {
  const [phase, setPhase] = useState<BreathPhase>(0);

  useEffect(() => {
    if (disabled || !active) return;

    let phaseIdx: BreathPhase = 0;
    let timeoutId: ReturnType<typeof setTimeout>;
    let stopped = false;

    const tick = () => {
      if (stopped) return;
      phaseIdx = ((phaseIdx + 1) % 4) as BreathPhase;
      setPhase(phaseIdx);
      timeoutId = setTimeout(tick, BREATH_DURATIONS[phaseIdx]);
    };

    // Pause when the tab is hidden; resume (re-anchored to phase 0) on return.
    const onVisibility = () => {
      if (document.hidden) {
        clearTimeout(timeoutId);
      } else if (!stopped) {
        timeoutId = setTimeout(tick, BREATH_DURATIONS[phaseIdx]);
      }
    };
    document.addEventListener("visibilitychange", onVisibility);

    timeoutId = setTimeout(tick, BREATH_DURATIONS[0]);

    return () => {
      stopped = true;
      clearTimeout(timeoutId);
      document.removeEventListener("visibilitychange", onVisibility);
    };
  }, [active, disabled]);

  return disabled ? 3 : phase;
}

"use client";

import { useSyncExternalStore } from "react";

const QUERY = "(prefers-reduced-motion: reduce)";

function subscribe(onChange: () => void): () => void {
  const mql = window.matchMedia(QUERY);
  mql.addEventListener("change", onChange);
  return () => mql.removeEventListener("change", onChange);
}

function getSnapshot(): boolean {
  return window.matchMedia(QUERY).matches;
}

function getServerSnapshot(): boolean {
  return false;
}

/**
 * True when the OS asks for reduced motion.
 * SSR-safe: the server snapshot is `false`; on the client the real value is
 * read synchronously, and live changes to the setting re-render immediately.
 * Under reduced motion the breath cue stops, the chasen draws fully, and the
 * whole ceremony is a calm static scroll.
 */
export function usePrefersReducedMotion(): boolean {
  return useSyncExternalStore(subscribe, getSnapshot, getServerSnapshot);
}

"use client";

import { useEffect, useRef } from "react";

/**
 * Reveals descendants marked with [data-reveal] as they enter the viewport,
 * by adding an `is-visible` class. The pre-reveal state (opacity + a small
 * rise, or the tategaki header's per-glyph cadence) lives in styles.css and
 * is gated behind the `.chado-js` root class — so every line of the ceremony
 * is plainly present when JavaScript never runs. The ceremony must read as a
 * finished document with JS off; a tea rite degrades to paper, not to blanks.
 *
 * Two flavors:
 *   data-reveal          — the element itself fades and rises (1.1s, the
 *                          ceremony's slower ease), with a 140ms stagger
 *                          between elements of the same observer batch, so a
 *                          screenful never moves as one slab.
 *   data-reveal="scene"  — the element does not animate itself; it only
 *                          receives `is-visible` so its descendants (tategaki
 *                          glyphs, beat lines) can run their own choreography.
 */
export function useReveal<T extends HTMLElement>(disabled: boolean) {
  const rootRef = useRef<T | null>(null);

  useEffect(() => {
    const root = rootRef.current;
    if (!root) return;
    const targets = Array.from(
      root.querySelectorAll<HTMLElement>("[data-reveal]"),
    );

    if (disabled || !("IntersectionObserver" in window)) {
      for (const el of targets) el.classList.add("is-visible");
      return;
    }

    const io = new IntersectionObserver(
      (hits) => {
        let batch = 0;
        for (const hit of hits) {
          if (!hit.isIntersecting) continue;
          const el = hit.target as HTMLElement;
          if (el.dataset.reveal !== "scene") {
            el.style.transitionDelay = `${batch * 140}ms`;
            batch += 1;
          }
          el.classList.add("is-visible");
          io.unobserve(el);
        }
      },
      { threshold: 0.18, rootMargin: "0px 0px -10% 0px" },
    );
    for (const el of targets) io.observe(el);
    return () => io.disconnect();
  }, [disabled]);

  return rootRef;
}

"use client";

import { useEffect, useRef } from "react";

/**
 * Drives a 0→1 scroll progress for a pinned chashitsu (tea-preparation
 * scene), written to the element as the `--ch-scrub` custom property. The
 * chasen whisk consumes it in CSS:
 *   stroke-dashoffset: calc(1 - var(--ch-scrub, 1))
 * on pathLength=1 bamboo-tine paths — so the whisk draws exactly as far as
 * the guest has scrolled, and the bowl's matcha surface blooms in only as
 * the preparation completes. The whole ceremony is paced so the whisk never
 * moves faster than the hand that summoned it.
 *
 * Discipline (rubric gate G3):
 * - All geometry is measured inside rAF: one getBoundingClientRect read,
 *   then one custom-property write — read before write, no layout thrash.
 * - The raw progress is lerp-smoothed with a dt-normalized factor
 *   (1 - 0.88^(dt/16.7)), so a 120Hz display does not scrub twice as fast
 *   as a 60Hz one. Half-life ≈ 5.4 frames.
 * - An IntersectionObserver starts/stops the loop, so an offscreen
 *   chashitsu costs zero frames. A visibilitychange listener also stops it
 *   when the tab is hidden.
 * - Disabled (reduced motion) or never mounted (no JS): the hook writes
 *   `--ch-scrub: 1` once and the CSS default of 1 leaves every tine drawn
 *   and the bowl full — a completed preparation, statically waiting.
 */
export function useScrollProgress<T extends HTMLElement>(disabled: boolean) {
  const ref = useRef<T | null>(null);

  useEffect(() => {
    const el = ref.current;
    if (!el) return;

    if (disabled) {
      el.style.setProperty("--ch-scrub", "1");
      return;
    }

    let raf = 0;
    let last = 0;
    let value: number | null = null;

    const frame = (now: number) => {
      raf = requestAnimationFrame(frame);
      const dt = Math.min(Math.max(now - last, 1), 48);
      last = now;

      // Read phase: one rect, one viewport height.
      const rect = el.getBoundingClientRect();
      const vh = window.innerHeight || 1;

      // The scrub runs from "scene center at 62% of the viewport" across
      // 90% of the scene's height, capped at ~1.2 viewports so tall
      // single-column (mobile) chashitsu still finish while in view.
      const center = rect.top + rect.height / 2;
      const span = Math.max(Math.min(rect.height * 0.9, vh * 1.2), 1);
      const raw = (vh * 0.62 - center) / span;
      const target = Math.min(1, Math.max(0, raw));

      if (value === null) {
        value = target; // first frame: no animated catch-up flash
      } else {
        value += (target - value) * (1 - Math.pow(0.88, dt / 16.7));
        if (Math.abs(target - value) < 0.0005) value = target;
      }

      // Write phase.
      el.style.setProperty("--ch-scrub", value.toFixed(4));
    };

    const start = () => {
      if (raf) return;
      last = performance.now();
      raf = requestAnimationFrame(frame);
    };
    const stop = () => {
      if (!raf) return;
      cancelAnimationFrame(raf);
      raf = 0;
    };

    const onVisibility = () => {
      if (document.hidden) stop();
      else start();
    };
    document.addEventListener("visibilitychange", onVisibility);

    if (!("IntersectionObserver" in window)) {
      start();
      return () => {
        stop();
        document.removeEventListener("visibilitychange", onVisibility);
      };
    }

    const io = new IntersectionObserver(
      (hits) => {
        for (const hit of hits) {
          if (hit.isIntersecting) start();
          else stop();
        }
      },
      { rootMargin: "25% 0px 25% 0px" },
    );
    io.observe(el);

    return () => {
      stop();
      io.disconnect();
      document.removeEventListener("visibilitychange", onVisibility);
    };
  }, [disabled]);

  return ref;
}

"use client";

import { useEffect, useRef, useState } from "react";
import "./styles.css";
import { cormorantGaramond, shipporiMincho } from "./fonts";
import Hero from "./components/Hero";
import Ceremony from "./components/Ceremony";
import ChasenDraw from "./components/ChasenDraw";
import Tokonoma from "./components/Tokonoma";
import OneBowl from "./components/OneBowl";
import Colophon from "./components/Colophon";
import { usePrefersReducedMotion } from "./hooks/usePrefersReducedMotion";
import { useReveal } from "./hooks/useReveal";

/**
 * CHADŌ (茶道) — the way of tea. A virtual tea ceremony, paced like the
 * four-hour rite compressed into one scroll: each beat is a breath. The
 * aesthetic is extreme wabi-sabi — aged washi, warm ink (never pure black),
 * and a single living accent of matcha green. The hero's title is set in
 * tategaki (縦書き), the authentic vertical reading direction that almost
 * no Western "Japanese-inspired" site uses; the chasen whisk draws itself
 * as you breathe the bowl into being; the whole ceremony exists so that
 * one bowl of tea can be received with full attention.
 *
 * Everything on screen is code — the whisk is SVG, the bowl is SVG, the
 * paper is feTurbulence. No photograph would be still enough.
 *
 * `.chado-js` is added imperatively on mount (a signal to CSS that JS is
 * alive, never React state): every pre-reveal style is gated behind it, and
 * with JavaScript off the full ceremony simply stands finished. The breath
 * cue's `active` state is React's, because the cue genuinely depends on the
 * hero being in view — no point breathing for an empty room.
 */
export default function ChadoPage() {
  const rootRef = useRef<HTMLDivElement | null>(null);
  const heroRef = useRef<HTMLDivElement | null>(null);
  const reduced = usePrefersReducedMotion();
  const revealRef = useReveal<HTMLDivElement>(reduced);
  const [cueActive, setCueActive] = useState(false);

  useEffect(() => {
    rootRef.current?.classList.add("chado-js");
    window.parent?.postMessage({ type: "oneshot:ready", slug: "chado" }, "*");
  }, []);

  // The breath cue runs only while the hero is the room the guest is in.
  // One IntersectionObserver, no scroll handlers. Reduced-motion disables
  // it entirely (cue stays inactive — the ceremony is paced by the reader).
  useEffect(() => {
    if (reduced) return;
    const hero = heroRef.current;
    if (!hero || !("IntersectionObserver" in window)) return;
    const io = new IntersectionObserver(
      (hits) => {
        for (const hit of hits) setCueActive(hit.isIntersecting);
      },
      { threshold: 0.25 },
    );
    io.observe(hero);
    return () => io.disconnect();
  }, [reduced]);

  return (
    <div
      ref={rootRef}
      className={`${shipporiMincho.variable} ${cormorantGaramond.variable} chado-root`}
    >
      <div ref={revealRef} className="chado-ceremony-doc">
        <div ref={heroRef}>
          <Hero cueActive={cueActive} />
        </div>

        <main>
          <Ceremony />

          <ChasenDraw
            notes={
              <>
                <h3 className="chado-chashitsu__step-title" lang="ja">
                  点前、四つの動き
                </h3>
                <p className="chado-chashitsu__step-sub">
                  Four motions of the temae — scroll draws the whisk.
                </p>

                <ol className="chado-chashitsu__steps">
                  <li data-reveal>
                    <span className="chado-chashitsu__step-no">i.</span>
                    <p className="chado-beat__p chado-beat__p--ja" lang="ja">
                      茶杓で抹茶を茶碗に移す。山一杯の緑。
                    </p>
                    <p className="chado-beat__p chado-beat__p--en">
                      The chashaku lifts the matcha into the bowl — one
                      bamboo scoop, a small green mountain.
                    </p>
                  </li>
                  <li data-reveal>
                    <span className="chado-chashitsu__step-no">ii.</span>
                    <p className="chado-beat__p chado-beat__p--ja" lang="ja">
                      湯を少しだけ注ぐ。最初は、わずかに。
                    </p>
                    <p className="chado-beat__p chado-beat__p--en">
                      A little hot water, first — only a little. The paste
                      comes before the tea.
                    </p>
                  </li>
                  <li data-reveal>
                    <span className="chado-chashitsu__step-no">iii.</span>
                    <p className="chado-beat__p chado-beat__p--ja" lang="ja">
                      茶筅を動かす。まっすぐに、速く、前と後ろへ。
                    </p>
                    <p className="chado-beat__p chado-beat__p--en">
                      The chasen moves — straight, fast, front and back. The
                      tines you see drawing now are this motion.
                    </p>
                  </li>
                  <li data-reveal>
                    <span className="chado-chashitsu__step-no">iv.</span>
                    <p className="chado-beat__p chado-beat__p--ja" lang="ja">
                      泡が立つ。碗の緑が、雪で覆われる。
                    </p>
                    <p className="chado-beat__p chado-beat__p--en">
                      The foam rises. The green of the bowl is covered, at
                      last, in snow.
                    </p>
                  </li>
                </ol>
              </>
            }
          />

          <Tokonoma />
          <OneBowl />
        </main>

        <Colophon />
      </div>

      {/* Aged washi grain: one static feTurbulence pass over everything.
          Fibers, not film grain — it never animates. Stillness is the
          material. */}
      <svg className="chado-grain" aria-hidden="true" focusable="false">
        <filter id="chado-grain-f">
          <feTurbulence
            type="fractalNoise"
            baseFrequency="0.62"
            numOctaves={2}
            seed="17"
            stitchTiles="stitch"
          />
          <feColorMatrix
            type="matrix"
            values="0 0 0 0 0.17  0 0 0 0 0.15  0 0 0 0 0.125  0 0 0 0.045 0"
          />
        </filter>
        <rect width="100%" height="100%" filter="url(#chado-grain-f)" />
      </svg>
    </div>
  );
}

/* ==========================================================================
   CHADŌ 茶道 — The Way of Tea
   washi-sumi-e · aged paper, warm ink, one matcha accent
   ma (間) is the design — the pause between beats is the ceremony
   Scoped by convention to .chado-root; classes prefixed chado-.
   ========================================================================== */

.chado-root {
  /* -- palette ------------------------------------------------------------ */
  --ch-washi: #e8e2d4;        /* the aged page — everything happens against it */
  --ch-washi-warm: #ece7da;   /* the page's lit skin — hero & climax ground */
  --ch-tokonoma: #d9d2c2;     /* the alcove — recessed, older paper */
  --ch-sumi: #2b2620;         /* warm ink — never pure black (11.61:1 on washi) */
  --ch-ink-soft: #6b6358;     /* sumi thinned — secondary text (4.58:1) */
  --ch-rule: #b8ad96;         /* hairlines only (1.4:1) — never text */
  --ch-matcha: #5d6b3a;       /* the one living accent — decorative & large (4.48:1) */
  --ch-matcha-deep: #4a5630;  /* matcha as text — AA on paper (6.10:1) */
  /* derived */
  --ch-rule-faint: rgba(184, 173, 150, 0.45);
  --ch-shadow: rgba(43, 38, 32, 0.12);

  /* -- type ---------------------------------------------------------------- */
  --ch-font-latin: var(--font-cormorant), "Cormorant Garamond", Georgia, serif;
  --ch-font-ja: var(--font-mincho), "Shippori Mincho", serif;
  /* Cormorant first: Latin resolves there, CJK falls through into Shippori */
  --ch-font-stack: var(--font-cormorant), var(--font-mincho),
    Georgia, serif;

  /* -- motion -------------------------------------------------------------- */
  --ch-ease-tea: cubic-bezier(0.16, 1, 0.3, 1);  /* entrances: soft, long tail */
  --ch-ease-bow: cubic-bezier(0.65, 0, 0.35, 1); /* the breath & bowl: weighted */
  --ch-reveal-ms: 1100ms;

  /* Scroll-scrub default: 1 = every tine drawn, bowl full. JS lowers it per
     chashitsu; reduced-motion and no-JS never touch it. */
  --ch-scrub: 1;

  position: relative;
  min-height: 100vh;
  min-height: 100svh;
  background: var(--ch-washi);
  color: var(--ch-sumi);
  font-family: var(--ch-font-stack);
  font-size: clamp(16px, 0.42vw + 14px, 19px);
  line-height: 1.85;
  overflow-x: hidden;
  overflow-x: clip;
  /* warm age-vignette — paper yellowed evenly in a drawer */
  background-image: radial-gradient(
    ellipse at center,
    transparent 55%,
    rgba(91, 80, 58, 0.06) 100%
  );
}

/* Japanese is a first language of this ceremony: Shippori, looser leading,
   a touch of positive tracking for mincho legibility. */
.chado-root :lang(ja) {
  font-family: var(--ch-font-ja);
  letter-spacing: 0.02em;
  line-height: 1.9;
}

/* Matcha selection, scoped to the entry root */
.chado-root ::selection {
  background: var(--ch-matcha);
  color: var(--ch-washi);
}

/* Keyboard focus: a matcha ring, offset like a tea-cloth mark */
.chado-root :focus-visible {
  outline: 2px solid var(--ch-matcha-deep);
  outline-offset: 3px;
  border-radius: 1px;
}

.chado-ceremony-doc {
  position: relative;
  z-index: 1;
}

/* The washi grain overlay — fixed, full viewport, pointer-transparent,
   below the content (z-index 0 on the root stacking context above). */
.chado-grain {
  position: fixed;
  inset: 0;
  width: 100%;
  height: 100%;
  pointer-events: none;
  z-index: 0;
  opacity: 0.9;
  mix-blend-mode: multiply;
}

/* ==========================================================================
   Shared — kicker, section titles
   ========================================================================== */

.chado-kicker {
  margin: 0 0 1.4rem;
  font-family: var(--ch-font-latin);
  font-size: 0.72rem;
  letter-spacing: 0.3em;
  text-transform: uppercase;
  color: var(--ch-ink-soft);
}

.chado-kicker::before {
  content: "";
  display: block;
  width: 3rem;
  height: 1px;
  margin-bottom: 1.1rem;
  background: var(--ch-matcha);
}

.chado-kicker :lang(ja) {
  letter-spacing: 0.18em;
}

.chado-kicker--center {
  text-align: center;
}

.chado-kicker--center::before {
  margin-inline: auto;
}

.chado-section-title {
  margin: 0 0 0.6rem;
  font-family: var(--ch-font-ja);
  font-weight: 500;
  font-size: clamp(1.9rem, 4.4vw, 3.1rem);
  line-height: 1.35;
  letter-spacing: 0.04em;
  color: var(--ch-sumi);
}

.chado-section-title--center {
  text-align: center;
}

.chado-section-sub {
  margin: 0;
  font-family: var(--ch-font-latin);
  font-style: italic;
  font-size: clamp(1rem, 1.8vw, 1.2rem);
  color: var(--ch-ink-soft);
}

.chado-section-sub--center {
  text-align: center;
}

/* ==========================================================================
   01 · Hero — the chashitsu gate, with the tategaki title
   ========================================================================== */

.chado-hero {
  position: relative;
  min-height: 100vh;
  min-height: 100svh;
  background: var(--ch-washi-warm);
  background-image: radial-gradient(
    ellipse at center,
    transparent 60%,
    rgba(91, 80, 58, 0.05) 100%
  );
  padding: clamp(24px, 6vw, 76px);
  display: flex;
  flex-direction: column;
}

.chado-hero__folio {
  margin: 0;
  font-family: var(--ch-font-latin);
  font-style: italic;
  font-size: 0.95rem;
  color: var(--ch-ink-soft);
}

.chado-hero__folio :lang(ja) {
  font-style: normal;
  font-family: var(--ch-font-ja);
}

.chado-hero__stage {
  flex: 1;
  display: grid;
  grid-template-columns: minmax(0, 1fr);
  grid-template-areas: "title" "col";
  gap: clamp(2.5rem, 6vh, 4rem) clamp(2rem, 6vw, 5rem);
  align-content: center;
  padding: clamp(2rem, 8vh, 5rem) 0;
}

@media (min-width: 860px) {
  .chado-hero__stage {
    grid-template-columns: minmax(0, 1fr) minmax(0, 1.4fr);
    grid-template-areas: "col title";
    align-items: center;
  }
}

/* -- the tategaki title 茶道 --------------------------------------------- */
.chado-tategaki {
  grid-area: title;
  margin: 0;
  font-family: var(--ch-font-ja);
  font-weight: 500;
  /* THE signature: vertical writing mode, right-to-left columns */
  writing-mode: vertical-rl;
  -webkit-writing-mode: vertical-rl;
  text-orientation: upright;
  font-size: clamp(7rem, 18vw, 14rem);
  line-height: 1.02;
  letter-spacing: 0.06em;
  color: var(--ch-sumi);
  justify-self: center;
  max-height: 80vh;
  max-height: 80svh;
}

@media (min-width: 860px) {
  .chado-tategaki {
    justify-self: end;
  }
}

.chado-tategaki__ch {
  display: block;
}

/* Tategaki glyph rise — JS-gated; the no-JS title is simply written. */
.chado-js .chado-tategaki__ch {
  animation: ch-tategaki-rise 1300ms var(--ch-ease-tea) both;
  animation-delay: calc(180ms + var(--ch-ci, 0) * 220ms);
}

/* -- the right-hand column: wordmark, proposition, breath cue ----------- */
.chado-hero__col {
  grid-area: col;
  max-width: 34rem;
}

.chado-hero__kicker {
  margin: 0 0 1rem;
  font-family: var(--ch-font-latin);
  font-size: 0.72rem;
  letter-spacing: 0.3em;
  text-transform: uppercase;
  color: var(--ch-ink-soft);
}

.chado-hero__kicker::before {
  content: "";
  display: inline-block;
  width: 2.4rem;
  height: 1px;
  margin-right: 0.8rem;
  vertical-align: middle;
  background: var(--ch-matcha);
}

.chado-hero__kicker :lang(ja) {
  letter-spacing: 0.16em;
}

.chado-hero__name {
  margin: 0 0 0.4rem;
  font-family: var(--ch-font-latin);
  font-weight: 500;
  font-size: clamp(2.6rem, 7vw, 4.2rem);
  line-height: 1;
  letter-spacing: 0.04em;
  color: var(--ch-sumi);
}

.chado-hero__reading {
  margin: 0 0 2.4rem;
  font-family: var(--ch-font-latin);
  font-style: italic;
  font-size: 1.05rem;
  color: var(--ch-ink-soft);
}

.chado-hero__reading :lang(ja) {
  font-style: normal;
  font-family: var(--ch-font-ja);
}

.chado-hero__proposition {
  margin: 0 0 1rem;
  max-width: 30rem;
  font-family: var(--ch-font-ja);
  font-size: clamp(1.05rem, 2vw, 1.3rem);
  line-height: 2;
  color: var(--ch-sumi);
}

.chado-hero__proposition--en {
  margin-bottom: 2.6rem;
  font-family: var(--ch-font-latin);
  font-size: 0.98em;
  line-height: 1.78;
  color: var(--ch-ink-soft);
}

/* Scroll prompt at the foot of the column */
.chado-hero__scrollhint {
  display: flex;
  align-items: center;
  gap: 1rem;
  margin: 3rem 0 0;
  font-family: var(--ch-font-latin);
  font-size: 0.78rem;
  letter-spacing: 0.22em;
  text-transform: uppercase;
  color: var(--ch-ink-soft);
}

.chado-hero__scrollhint :lang(ja) {
  font-family: var(--ch-font-ja);
  letter-spacing: 0.12em;
  text-transform: none;
}

.chado-hero__scrollline {
  display: block;
  width: 3.5rem;
  height: 1px;
  background: var(--ch-rule);
}

/* ==========================================================================
   The breath cue — the ceremonial clock (4-4-4 box breath)
   ========================================================================== */

.chado-breath {
  position: relative;
  display: flex;
  align-items: center;
  gap: 1.4rem;
  margin: 2.4rem 0 0;
  min-height: 4rem;
}

.chado-breath__orb {
  position: relative;
  display: block;
  width: 3.2rem;
  height: 3.2rem;
  border-radius: 50%;
  background: var(--ch-matcha);
  flex: 0 0 auto;
  /* the breathing scale — keyed off data-breath so it runs on the compositor */
  transform: scale(0.92);
  transform-origin: center;
  transition: transform 4000ms cubic-bezier(0.33, 1, 0.68, 1); /* ease-out inhale */
}

.chado-breath[data-breath="0"] .chado-breath__orb {
  transform: scale(1);
  transition-duration: 4000ms;
  transition-timing-function: cubic-bezier(0.33, 1, 0.68, 1);
}

.chado-breath[data-breath="1"] .chado-breath__orb {
  transform: scale(1);
  transition-duration: 4000ms;
  transition-timing-function: linear;
}

.chado-breath[data-breath="2"] .chado-breath__orb {
  transform: scale(0.92);
  transition-duration: 4000ms;
  transition-timing-function: cubic-bezier(0.32, 0, 0.67, 0); /* ease-in exhale */
}

.chado-breath[data-breath="3"] .chado-breath__orb {
  transform: scale(0.92);
  transition-duration: 2000ms;
  transition-timing-function: linear;
}

/* two faint rings that ride the breath — opacity-only ambient */
.chado-breath__rings {
  position: absolute;
  left: 0;
  top: 50%;
  width: 3.2rem;
  height: 3.2rem;
  transform: translateY(-50%);
  pointer-events: none;
}

.chado-breath__ring {
  position: absolute;
  inset: 0;
  border-radius: 50%;
  border: 1px solid var(--ch-matcha);
  opacity: 0;
}

.chado-breath[data-breath="0"] .chado-breath__ring--1 {
  animation: ch-ring-out 4000ms cubic-bezier(0.33, 1, 0.68, 1) both;
}

.chado-breath[data-breath="2"] .chado-breath__ring--2 {
  animation: ch-ring-out 4000ms cubic-bezier(0.32, 0, 0.67, 0) both;
}

.chado-breath__label {
  display: flex;
  flex-direction: column;
  gap: 0.15rem;
  font-family: var(--ch-font-latin);
  line-height: 1.3;
}

.chado-breath__ja {
  font-family: var(--ch-font-ja);
  font-size: 1.1rem;
  color: var(--ch-sumi);
  letter-spacing: 0.1em;
}

.chado-breath__en {
  font-size: 0.74rem;
  letter-spacing: 0.24em;
  text-transform: uppercase;
  color: var(--ch-ink-soft);
}

/* the label cross-fades on phase change */
.chado-breath__label {
  animation: ch-label-fade 320ms var(--ch-ease-tea) both;
}

/* ==========================================================================
   02 · Ceremony beats — four turns, each a held breath (massive ma)
   ========================================================================== */

.chado-ceremony {
  padding: clamp(110px, 22vh, 240px) clamp(20px, 6vw, 48px);
}

.chado-ceremony__head {
  max-width: 44rem;
  margin: 0 auto clamp(5rem, 14vh, 9rem);
}

.chado-ceremony__beats {
  list-style: none;
  margin: 0;
  padding: 0;
  max-width: 60rem;
  margin-inline: auto;
  display: flex;
  flex-direction: column;
  /* the ma between beats — vast, deliberate */
  gap: clamp(6rem, 18vh, 12rem);
}

.chado-beat {
  display: grid;
  grid-template-columns: minmax(0, 1fr);
  gap: 1.4rem 3rem;
}

@media (min-width: 820px) {
  .chado-beat {
    grid-template-columns: 5rem minmax(0, 1fr);
  }
}

.chado-beat__index {
  display: flex;
  align-items: flex-start;
  gap: 1rem;
}

@media (min-width: 820px) {
  .chado-beat__index {
    flex-direction: column;
    gap: 1.2rem;
  }
}

.chado-beat__no {
  font-family: var(--ch-font-ja);
  font-size: clamp(1.8rem, 4vw, 2.6rem);
  line-height: 1;
  color: var(--ch-matcha-deep);
}

.chado-beat__rule {
  display: block;
  flex: 1;
  min-width: 2rem;
  height: 1px;
  background: var(--ch-rule-faint);
  margin-top: 1.2rem;
}

@media (min-width: 820px) {
  .chado-beat__rule {
    width: 100%;
    margin-top: 0;
  }
}

.chado-beat__title {
  margin: 0 0 1.4rem;
  font-family: var(--ch-font-ja);
  font-weight: 500;
  font-size: clamp(1.4rem, 3vw, 1.9rem);
  line-height: 1.4;
  color: var(--ch-sumi);
  display: flex;
  flex-wrap: wrap;
  align-items: baseline;
  gap: 0.6rem 1.2rem;
}

.chado-beat__title em {
  font-family: var(--ch-font-latin);
  font-style: italic;
  font-weight: 400;
  font-size: 0.62em;
  color: var(--ch-ink-soft);
}

.chado-beat__p {
  margin: 0;
  max-width: 34rem;
}

.chado-beat__p--ja {
  margin-bottom: 0.8rem;
  line-height: 2.05;
}

.chado-beat__p--en {
  margin-bottom: 0;
  font-family: var(--ch-font-latin);
  font-size: 0.95em;
  line-height: 1.74;
  color: var(--ch-ink-soft);
}

/* ==========================================================================
   03 · The chashitsu — the chasen draw-on (scroll-scrub-pinned + svg-line-draw)
   ========================================================================== */

.chado-chashitsu {
  padding: clamp(110px, 22vh, 220px) clamp(20px, 6vw, 48px);
}

.chado-chashitsu__head {
  max-width: 44rem;
  margin: 0 auto clamp(4rem, 10vh, 6rem);
}

.chado-chashitsu__scene {
  display: grid;
  grid-template-columns: minmax(0, 1fr);
  gap: clamp(2.5rem, 6vh, 4rem) clamp(3rem, 6vw, 5rem);
  max-width: 74rem;
  margin-inline: auto;
}

@media (min-width: 900px) {
  .chado-chashitsu__scene {
    grid-template-columns: minmax(0, 5fr) minmax(0, 6fr);
  }

  /* the pin: the plate holds while the preparation text flows past */
  .chado-chashitsu__plate {
    position: sticky;
    top: clamp(4rem, 12vh, 7rem);
    align-self: start;
  }
}

.chado-chashitsu__plate {
  margin: 0;
}

.chado-chashitsu__art {
  display: block;
  width: 100%;
  max-width: 26rem;
  height: auto;
  margin-inline: auto;
}

.chado-chashitsu__cap {
  margin: 1.2rem auto 0;
  max-width: 26rem;
  font-size: 0.82rem;
  line-height: 1.6;
  color: var(--ch-ink-soft);
  display: grid;
  gap: 0.2rem;
}

.chado-chashitsu__cap em {
  font-family: var(--ch-font-latin);
}

/* The chasen — the handle & node are static; the tines draw with scroll. */
.chado-chasen__handle,
.chado-chasen__tine {
  fill: none;
  stroke: var(--ch-sumi);
  stroke-linecap: round;
  stroke-width: 2.4;
}

.chado-chasen__handle {
  stroke-width: 6;
  stroke: var(--ch-sumi);
  /* handle always fully present */
  stroke-dasharray: none;
}

.chado-chasen__node {
  fill: var(--ch-sumi);
  opacity: 0.85;
}

.chado-chasen__tine {
  /* pathLength=1, dashoffset = 1 − scrub. Default scrub 1 → tine drawn. */
  stroke-dasharray: 1 1;
  stroke-dashoffset: calc(1 - var(--ch-scrub, 1));
  stroke-width: 1.6;
  opacity: 0.92;
}

.chado-chasen__tine--inner {
  stroke-width: 1.2;
  opacity: 0.7;
}

/* The bowl — the shell draws with the whisk; the tea blooms at the end. */
.chado-bowl__shell,
.chado-bowl__rim,
.chado-bowl__foam {
  fill: none;
  stroke: var(--ch-sumi);
  stroke-width: 2.6;
  stroke-linecap: round;
  stroke-linejoin: round;
}

.chado-bowl__shell,
.chado-bowl__foam {
  /* pathLength=1 is set as the SVG attribute; here we only drive the draw */
  stroke-dasharray: 1 1;
  stroke-dashoffset: calc(1 - var(--ch-scrub, 1));
}

.chado-bowl__rim {
  fill: var(--ch-tokonoma);
  stroke-width: 2.2;
}

/* the matcha surface — blooms only as the preparation completes:
   opacity calc(scrub·5 − 4) maps scrub 0.8→1 onto 0→1; the browser
   clamps opacity to [0,1] for free. Default scrub 1 → tea present. */
.chado-bowl__tea {
  fill: var(--ch-matcha);
  opacity: calc(var(--ch-scrub, 1) * 5 - 4);
}

/* -- the preparation text ---------------------------------------------- */
.chado-chashitsu__text {
  max-width: 32rem;
}

.chado-chashitsu__step-title {
  margin: 0 0 0.4rem;
  font-family: var(--ch-font-ja);
  font-weight: 500;
  font-size: 1.5rem;
  color: var(--ch-sumi);
}

.chado-chashitsu__step-sub {
  margin: 0 0 2rem;
  font-family: var(--ch-font-latin);
  font-style: italic;
  font-size: 0.98rem;
  color: var(--ch-ink-soft);
}

.chado-chashitsu__steps {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  flex-direction: column;
  gap: clamp(1.8rem, 4vh, 2.8rem);
}

.chado-chashitsu__steps li {
  display: grid;
  grid-template-columns: 2.5rem minmax(0, 1fr);
  gap: 0.4rem 1rem;
}

.chado-chashitsu__step-no {
  font-family: var(--ch-font-latin);
  font-style: italic;
  font-size: 0.92rem;
  color: var(--ch-matcha-deep);
  padding-top: 0.15rem;
}

/* ==========================================================================
   04 · Tokonoma — the alcove (paper on paper, the second tategaki)
   ========================================================================== */

.chado-tokonoma {
  padding: clamp(110px, 22vh, 220px) clamp(20px, 6vw, 48px);
}

.chado-tokonoma__head {
  max-width: 44rem;
  margin: 0 auto clamp(4rem, 10vh, 6rem);
}

.chado-tokonoma__recess {
  position: relative;
  max-width: 68rem;
  margin-inline: auto;
  background: var(--ch-tokonoma);
  /* the alcove frame — rebated from the edge, sumi hairline */
  padding: clamp(3rem, 8vh, 5rem) clamp(2.5rem, 6vw, 5rem);
  display: grid;
  grid-template-columns: minmax(0, 1fr);
  gap: clamp(2.5rem, 6vh, 4rem);
  align-items: center;
  justify-items: center;
}

@media (min-width: 860px) {
  .chado-tokonoma__recess {
    grid-template-columns: minmax(0, 1fr) minmax(0, 1fr);
  }
}

/* faint alcove frame line */
.chado-tokonoma__recess::before {
  content: "";
  position: absolute;
  inset: 2.2vw 2.2vw;
  border: 1px solid var(--ch-rule-faint);
  pointer-events: none;
}

.chado-tokonoma__paper {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  pointer-events: none;
  opacity: 0.85;
  mix-blend-mode: multiply;
}

/* -- the hanging scroll: the tea poem in tategaki ---------------------- */
.chado-scroll {
  position: relative;
  z-index: 1;
  margin: 0;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 0.6rem;
}

.chado-scroll__rod {
  width: clamp(4rem, 9vw, 5.5rem);
  height: 4px;
  background: var(--ch-sumi);
  border-radius: 2px;
  opacity: 0.85;
}

.chado-scroll__rod--bottom {
  height: 6px;
  width: clamp(4.4rem, 10vw, 6rem);
}

.chado-scroll__poem {
  margin: 0;
  padding: 1.2rem 0.8rem;
  font-family: var(--ch-font-ja);
  font-weight: 500;
  writing-mode: vertical-rl;
  -webkit-writing-mode: vertical-rl;
  text-orientation: upright;
  font-size: clamp(1.3rem, 2.6vw, 1.8rem);
  line-height: 1.9;
  letter-spacing: 0.08em;
  color: var(--ch-sumi);
  max-height: 60vh;
  max-height: 60svh;
}

.chado-scroll__poem span {
  display: block;
}

.chado-scroll__cap {
  margin-top: 0.6rem;
  max-width: 16rem;
  font-family: var(--ch-font-latin);
  font-style: italic;
  font-size: 0.82rem;
  line-height: 1.55;
  text-align: center;
  color: var(--ch-ink-soft);
}

/* -- the ikebana — one stem, drawn once on reveal ---------------------- */
.chado-ikebana {
  position: relative;
  z-index: 1;
  margin: 0;
  text-align: center;
}

.chado-ikebana__art {
  display: block;
  width: clamp(8rem, 18vw, 11rem);
  height: auto;
  margin-inline: auto;
}

.chado-ikebana__vessel {
  fill: var(--ch-sumi);
  opacity: 0.88;
}

.chado-ikebana__water {
  fill: none;
  stroke: var(--ch-sumi);
  stroke-width: 1;
  opacity: 0.4;
}

.chado-ikebana__stem,
.chado-ikebana__leaf {
  fill: none;
  stroke: var(--ch-sumi);
  stroke-linecap: round;
  stroke-width: 2;
}

.chado-ikebana__leaf {
  fill: var(--ch-sumi);
  fill-opacity: 0.12;
  stroke-width: 1.6;
}

/* the stem & leaf draw once, time-based, on reveal — the only time-based
   draw on the page (every other stroke is scroll-scrubbed or static) */
.chado-ikebana__stem,
.chado-ikebana__leaf {
  stroke-dasharray: 1 1;
  stroke-dashoffset: 0;
}

.chado-js .chado-tokonoma [data-reveal] .chado-ikebana__stem,
.chado-js .chado-tokonoma [data-reveal] .chado-ikebana__leaf {
  stroke-dashoffset: 1;
}

.chado-js .chado-tokonoma [data-reveal].is-visible .chado-ikebana__stem {
  stroke-dashoffset: 0;
  transition: stroke-dashoffset 1600ms var(--ch-ease-tea) 200ms;
}

.chado-js .chado-tokonoma [data-reveal].is-visible .chado-ikebana__leaf {
  stroke-dashoffset: 0;
  transition: stroke-dashoffset 1200ms var(--ch-ease-tea) 900ms;
}

/* the one matcha bloom — the alcove's single accent */
.chado-ikebana__bloom {
  fill: var(--ch-matcha);
}

.chado-ikebana__bloom-core {
  fill: var(--ch-matcha-deep);
}

.chado-ikebana__cap {
  margin-top: 0.8rem;
  font-size: 0.8rem;
  color: var(--ch-ink-soft);
}

.chado-ikebana__cap em {
  font-family: var(--ch-font-latin);
  font-style: italic;
}

.chado-ikebana__cap :lang(ja) {
  font-family: var(--ch-font-ja);
}

/* ==========================================================================
   05 · One bowl — the climax (一服)
   ========================================================================== */

.chado-bowlsec {
  padding: clamp(130px, 26vh, 260px) clamp(20px, 6vw, 48px);
  background: var(--ch-washi-warm);
  background-image: radial-gradient(
    ellipse at center,
    transparent 58%,
    rgba(91, 80, 58, 0.05) 100%
  );
}

.chado-bowlsec__inner {
  max-width: 44rem;
  margin-inline: auto;
  text-align: center;
}

.chado-bowlsec__art {
  display: block;
  width: min(22rem, 80%);
  height: auto;
  margin: 0 auto clamp(2rem, 5vh, 3rem);
}

/* the steam — the page's one ambient loop (opacity/transform only) */
.chado-bowlsec__steam {
  opacity: 0.5;
}

.chado-bowlsec__wisp {
  fill: none;
  stroke: var(--ch-sumi);
  stroke-width: 1.4;
  stroke-linecap: round;
  opacity: 0.55;
  transform-origin: center bottom;
  animation: ch-steam 7.2s ease-in-out infinite;
}

.chado-bowlsec__wisp--2 {
  animation-delay: -2.4s;
  opacity: 0.4;
}

.chado-bowlsec__wisp--3 {
  animation-delay: -4.8s;
  opacity: 0.45;
}

.chado-bowlsec__shell,
.chado-bowlsec__rim {
  fill: none;
  stroke: var(--ch-sumi);
  stroke-width: 2.6;
  stroke-linecap: round;
  stroke-linejoin: round;
}

.chado-bowlsec__rim {
  fill: var(--ch-washi-warm);
  stroke-width: 2.2;
}

.chado-bowlsec__tea {
  fill: var(--ch-matcha);
}

.chado-bowlsec__foam {
  fill: none;
  stroke: var(--ch-washi-warm);
  stroke-width: 2.4;
  stroke-linecap: round;
  opacity: 0.85;
}

.chado-bowlsec__title {
  margin: 0 0 0.3rem;
  font-family: var(--ch-font-ja);
  font-weight: 500;
  font-size: clamp(3.5rem, 9vw, 5.5rem);
  line-height: 1;
  letter-spacing: 0.08em;
  color: var(--ch-sumi);
}

.chado-bowlsec__reading {
  margin: 0 0 2.4rem;
  font-family: var(--ch-font-latin);
  font-style: italic;
  font-size: 1.05rem;
  color: var(--ch-ink-soft);
}

.chado-bowlsec__line {
  margin: 0 auto 1rem;
  max-width: 28rem;
  font-family: var(--ch-font-latin);
  font-size: 1.02rem;
  line-height: 1.78;
  color: var(--ch-ink-soft);
}

.chado-bowlsec__line--ja {
  margin-bottom: 0.8rem;
  font-family: var(--ch-font-ja);
  font-size: 1.1rem;
  line-height: 2;
  color: var(--ch-sumi);
}

.chado-bowlsec__seal {
  margin: 2.8rem 0 0;
  font-family: var(--ch-font-ja);
  font-size: 1.3rem;
  letter-spacing: 0.12em;
  color: var(--ch-matcha-deep);
}

/* ==========================================================================
   06 · Colophon — the closing
   ========================================================================== */

.chado-colophon {
  padding: clamp(90px, 16vh, 170px) clamp(20px, 6vw, 48px)
    clamp(96px, 16vh, 180px);
  border-top: 1px solid var(--ch-rule-faint);
}

.chado-colophon__inner {
  max-width: 44rem;
  margin-inline: auto;
}

.chado-colophon__title {
  margin: 0 0 0.4rem;
  font-family: var(--ch-font-ja);
  font-weight: 500;
  font-size: clamp(2rem, 5vw, 2.8rem);
  color: var(--ch-sumi);
}

.chado-colophon__sub {
  margin: 0 0 3rem;
  font-family: var(--ch-font-latin);
  font-style: italic;
  font-size: 0.98rem;
  color: var(--ch-ink-soft);
}

.chado-colophon__ledger {
  margin: 0 0 3.2rem;
  max-width: 44rem;
}

.chado-colophon__ledger > div {
  display: flex;
  flex-wrap: wrap;
  gap: 0.2rem 1.5rem;
  padding: 0.7rem 0;
  border-bottom: 1px dotted var(--ch-rule);
}

.chado-colophon__ledger dt {
  flex: 0 0 12rem;
  font-family: var(--ch-font-latin);
  font-size: 0.72rem;
  letter-spacing: 0.2em;
  text-transform: uppercase;
  color: var(--ch-ink-soft);
  line-height: 2.2;
}

.chado-colophon__ledger dt :lang(ja) {
  font-family: var(--ch-font-ja);
  letter-spacing: 0.1em;
  text-transform: none;
}

.chado-colophon__ledger dd {
  flex: 1 1 16rem;
  margin: 0;
  font-size: 0.95rem;
  line-height: 1.7;
}

.chado-colophon__ledger dd :lang(ja) {
  font-family: var(--ch-font-ja);
}

.chado-colophon__close {
  margin: 0 0 1rem;
  max-width: 32rem;
  font-family: var(--ch-font-ja);
  font-size: 1.05rem;
  line-height: 2;
  color: var(--ch-sumi);
}

.chado-colophon__close--en {
  margin-bottom: 3rem;
  font-family: var(--ch-font-latin);
  font-size: 0.98em;
  line-height: 1.74;
  color: var(--ch-ink-soft);
}

.chado-colophon__legal {
  margin: 0 0 1.6rem;
  font-family: var(--ch-font-latin);
  font-size: 0.86rem;
  line-height: 1.7;
  color: var(--ch-ink-soft);
}

.chado-colophon__top {
  display: inline-block;
  font-family: var(--ch-font-latin);
  font-size: 0.9rem;
  color: var(--ch-sumi);
  text-decoration: none;
  border-bottom: 1px solid var(--ch-rule);
  padding-bottom: 1px;
  transition: color 300ms var(--ch-ease-tea);
}

.chado-colophon__top :lang(ja) {
  font-family: var(--ch-font-ja);
}

.chado-colophon__top:hover,
.chado-colophon__top:focus-visible {
  color: var(--ch-matcha-deep);
  border-bottom-color: var(--ch-matcha);
}

/* ==========================================================================
   Scroll reveals — JS-gated pre-state, transform/opacity only
   ========================================================================== */

.chado-js [data-reveal] {
  opacity: 0;
  transform: translateY(16px);
  transition:
    opacity var(--ch-reveal-ms) var(--ch-ease-tea),
    transform var(--ch-reveal-ms) var(--ch-ease-tea);
  will-change: opacity, transform;
}

.chado-js [data-reveal].is-visible {
  opacity: 1;
  transform: none;
}

/* ==========================================================================
   Keyframes — transform / opacity only
   ========================================================================== */

@keyframes ch-tategaki-rise {
  from {
    opacity: 0;
    transform: translateY(0.22em);
  }
  to {
    opacity: 1;
    transform: none;
  }
}

@keyframes ch-label-fade {
  from {
    opacity: 0;
  }
  to {
    opacity: 1;
  }
}

@keyframes ch-ring-out {
  from {
    opacity: 0.5;
    transform: scale(0.9);
  }
  to {
    opacity: 0;
    transform: scale(1.9);
  }
}

@keyframes ch-steam {
  0%,
  100% {
    opacity: 0.18;
    transform: translateY(2px);
  }
  50% {
    opacity: 0.6;
    transform: translateY(-3px);
  }
}

/* ==========================================================================
   Reduced motion — one calm, fully-composed static ceremony
   - breath cue: orb sits full & still (phase "rest"), no rings, no label fade
   - tategaki: rendered statically, no glyph rise
   - chasen: every tine drawn, bowl full (scrub stays 1), plate unpins
   - ikebana stem: drawn, no draw transition
   - steam: still
   - reveals: present, no motion
   ========================================================================== */

@media (prefers-reduced-motion: reduce) {
  .chado-js .chado-tategaki__ch {
    animation: none;
  }

  .chado-breath__orb,
  .chado-breath[data-breath="0"] .chado-breath__orb,
  .chado-breath[data-breath="1"] .chado-breath__orb,
  .chado-breath[data-breath="2"] .chado-breath__orb,
  .chado-breath[data-breath="3"] .chado-breath__orb {
    transform: scale(1);
    transition: none;
  }

  .chado-breath__ring,
  .chado-breath[data-breath="0"] .chado-breath__ring--1,
  .chado-breath[data-breath="2"] .chado-breath__ring--2 {
    animation: none;
    opacity: 0;
  }

  .chado-breath__label {
    animation: none;
  }

  .chado-js [data-reveal] {
    opacity: 1;
    transform: none;
    transition: none;
  }

  .chado-chashitsu__plate {
    position: static;
  }

  .chado-js .chado-tokonoma [data-reveal] .chado-ikebana__stem,
  .chado-js .chado-tokonoma [data-reveal] .chado-ikebana__leaf,
  .chado-js
    .chado-tokonoma
    [data-reveal].is-visible
    .chado-ikebana__stem,
  .chado-js
    .chado-tokonoma
    [data-reveal].is-visible
    .chado-ikebana__leaf {
    stroke-dashoffset: 0;
    transition: none;
  }

  .chado-bowlsec__wisp,
  .chado-bowlsec__wisp--2,
  .chado-bowlsec__wisp--3 {
    animation: none;
    opacity: 0.3;
  }
}

/* ==========================================================================
   Small screens — the tategaki stays upright but smaller; grids collapse
   (handled inline above). Ensure the title never overflows narrow widths.
   ========================================================================== */

@media (max-width: 480px) {
  .chado-tategaki {
    font-size: clamp(5rem, 26vw, 7rem);
    max-height: 60vh;
    max-height: 60svh;
  }

  .chado-scroll__poem {
    font-size: 1.15rem;
    max-height: 50vh;
    max-height: 50svh;
  }
}
